var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CCN No. BDM003M000027-03\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 대상자 진술","JPN":"CCN No. BDM003M000027-03\\n<color=#ffd34c>1級要因</color> 閲覧承認資料\\n付録: 対象者陳述","ENG":"CCN No. BDM003M000027-03\\n<color=#ffd34c>Class 1 Erosion</color> Approval Document\\nAppendix: Target Extermination","TWN":"(TWN)CCN No. BDM003M000027-03\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 대상자 진술"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"젠장! 젠장!! 안전하다며! 루트대로만 가면 괜찮다며!!","JPN":"くそ!くそ!!安全であると!ルート大にだけ行けば大丈夫であると!!","ENG":"Rear! Rear!! You said it was safe! You said we'd be fine if we stuck to the route!!","TWN":"(TWN)젠장! 젠장!! 안전하다며! 루트대로만 가면 괜찮다며!!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}},"sfx":"FX_CUTSCEN_RIFLE_FIRE_02"},{"id":"L5_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"이게 뭐야! 왜 이렇게 많은 거냐고!","JPN":"これが何なの!なぜこのように多くのことかと!","ENG":"What the hell is this! Why are there so many of them!","TWN":"(TWN)이게 뭐야! 왜 이렇게 많은 거냐고!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"빌어먹을! 스탠이 당했어! 스탠! 스탠!!","JPN":"畜生!ステンがあった!ステン!ステン!!","ENG":"Damn it! Stan's been hit! Stan! Stan!!","TWN":"(TWN)빌어먹을! 스탠이 당했어! 스탠! 스탠!!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"이미 늦었어! 한눈 팔지 말고 닥치는 대로 쏴 버려!","JPN":"もう遅れた!わき目をふらずに近づき次第射ってしまう!","ENG":"It's too late! Stop gawking and shoot everything that moves!","TWN":"(TWN)이미 늦었어! 한눈 팔지 말고 닥치는 대로 쏴 버려!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_RIFLE_FIRE_02"},{"id":"L12_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"덕분에 침식체 군집에게 포위 당해서 그대로 죽는 줄 알았습니다.\\n그랬는데......","JPN":"おかげで侵食体群集に包囲されてそのまま死ぬと思いました。\\nそうだったが......","ENG":"I thought we were done for, surrounded by that horde of erosion creatures.\\nBut then......","TWN":"(TWN)덕분에 침식체 군집에게 포위 당해서 그대로 죽는 줄 알았습니다.\\n그랬는데......"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"놈들이 물러난다!","JPN":"やつが退く!","ENG":"They're retreating!","TWN":"(TWN)놈들이 물러난다!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"진짜냐! 빌어먹을! 살았다! 살았다고!","JPN":"本当か!畜生!暮らした!暮らしたと!","ENG":"Is it real! Damn it! We survived! We're alive!","TWN":"(TWN)진짜냐! 빌어먹을! 살았다! 살았다고!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"좋아하기엔 아직 일러! 살아 있는 놈들을 빨리 집결해! 바로 본대로 복귀한다!","JPN":"好きにはまだ和露!生きているやつを早く集結する!直視したとおり復帰する!","ENG":"It's too soon to celebrate! Gather the survivors quickly! We return to the main force immediately!","TWN":"(TWN)좋아하기엔 아직 일러! 살아 있는 놈들을 빨리 집결해! 바로 본대로 복귀한다!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L18_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"헉...... 허억...... 헉......","JPN":"はっと......許億......はっと......","ENG":"Hngh... *gasp*... hngh......","TWN":"(TWN)헉...... 허억...... 헉......"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"괜찮아, 아저씨? 다친 데는 없어?","JPN":"大丈夫で、おじさん?けがをしたところはないの?","ENG":"Are you okay, mister? Are you hurt anywhere?","TWN":"(TWN)괜찮아, 아저씨? 다친 데는 없어?"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L22_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"너......? 어디 있다가 왔길래 온몸이 피투성이야?","JPN":"君......?どこにあって来たから全身が血だらけなの?","ENG":"You...? Where did you come from? You're covered in blood.","TWN":"(TWN)너......? 어디 있다가 왔길래 온몸이 피투성이야?"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L23_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아, 이거...?\\n침식체들이랑 싸우느라. 숫자가 너무 많더라고.","JPN":"あ、これ...?\\n侵食体と戦うために。数字があまりにも多かったって。","ENG":"Ah, this...? I was fighting the erosion creatures. There were so many of them.","TWN":"(TWN)아, 이거...?\\n침식체들이랑 싸우느라. 숫자가 너무 많더라고."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L24_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"뭐? 너 어디 있었는데?","JPN":"何?君どこにあったが?","ENG":"What? Where were you?","TWN":"(TWN)뭐? 너 어디 있었는데?"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L25_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"저─기 앞쪽에. 엄청 몰려오더라고.","JPN":"低─期先方に。すごく群がって来ていたって。","ENG":"Upーahead. They were swarming in huge numbers.","TWN":"(TWN)저─기 앞쪽에. 엄청 몰려오더라고."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L26_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"미안해, 아저씨. 얌전히 따라오라고만 했는데 깜빡했어.","JPN":"ごめん、おじさん。おとなしくついて来るとしたがうっかりした。","ENG":"Sorry, mister. You told me to just follow behind, but I forgot.","TWN":"(TWN)미안해, 아저씨. 얌전히 따라오라고만 했는데 깜빡했어."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L27_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"아, 아니, 그런 것보다 너 괜찮은 거냐. 팔.... 부러진 것 같은데.","JPN":"あ、分かるから、そうするのより君大丈夫であるのか。腕....折れたようであるが。","ENG":"Ah, no, more importantly, are you okay? Your arm... looks broken.","TWN":"(TWN)아, 아니, 그런 것보다 너 괜찮은 거냐. 팔.... 부러진 것 같은데."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L28_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"사실은 갈비뼈도 몇 대 나간 것 같아.","JPN":"事実は肋骨も何台出たようである。","ENG":"I think I also have a few broken ribs, actually.","TWN":"(TWN)사실은 갈비뼈도 몇 대 나간 것 같아."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L29_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그런데 왜 입도 뻥긋 안 하고 있어!","JPN":"ところでなぜ口もにっこりとしていない!","ENG":"Then why aren't you even saying anything about it!","TWN":"(TWN)그런데 왜 입도 뻥긋 안 하고 있어!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L30_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"난 강하니까 괜찮다구. 이런 거 금방 아물 거야.\\n다른 다친 사람들 챙기기도 바쁘잖아.","JPN":"私は強いから大丈夫であるよ。このようなことすぐ癒えるだろう。\\n他のけがをした人々得たり忙しいんじゃないの。","ENG":"I'm strong so I'm fine. This will heal quickly. You need to take care of the other injured people.","TWN":"(TWN)난 강하니까 괜찮다구. 이런 거 금방 아물 거야.\\n다른 다친 사람들 챙기기도 바쁘잖아."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L31_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":".......","ENG":".......","TWN":"(TWN)......."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L32_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그럼 난 다른 녀석들이 더 있나 돌아보고 올게!\\n아저씨는 여기서 쉬고 있어!","JPN":"それでは出た他の野郎どもがさらにいるが振り返って来るよ!\\nおじさんはここで休んでいる!","ENG":"Then I'll go check if there are more of those things! You rest here, mister!","TWN":"(TWN)그럼 난 다른 녀석들이 더 있나 돌아보고 올게!\\n아저씨는 여기서 쉬고 있어!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L35_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"......제대로 걷지도 못하면서, 무슨 소릴 하는 거야.","JPN":"......十分に歩くこともできないのに、何の話をすることなの。","ENG":"......You can't even walk properly, what are you talking about.","TWN":"(TWN)......제대로 걷지도 못하면서, 무슨 소릴 하는 거야."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"돌아가는 길에 그 애가 막고 있던 장소를 지나쳤습니다.","JPN":"帰る道にその子が防いでいた場所を通り過ぎました。","ENG":"On the way back, I passed the place where she had been holding them off.","TWN":"(TWN)돌아가는 길에 그 애가 막고 있던 장소를 지나쳤습니다."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"수십.... 아니, 수백 마리는 되더군요.","JPN":"数十....いや、数百匹はなりますね。","ENG":"There were dozens... no, hundreds of them.","TWN":"(TWN)수십.... 아니, 수백 마리는 되더군요."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"돈 한 푼 안 받으면서, 별로 강하지도 않은 주제에 왜 그렇게 목숨을 걸고 싸웠을까 생각해 봤는데......","JPN":"お金一文受けなくて、あまり強くない主題になぜそのように命をかけて戦っただろうか考えてみたが......","ENG":"I wondered why she would fight with her life on the line without getting a single penny, even though she wasn't particularly strong......","TWN":"(TWN)돈 한 푼 안 받으면서, 별로 강하지도 않은 주제에 왜 그렇게 목숨을 걸고 싸웠을까 생각해 봤는데......"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그냥, 좋은 녀석이란 것 말고는 다른 답이 안 나오더라고요.","JPN":"そのまま、良いやつということでなく別の答えが出ないんですよ。","ENG":"I couldn't come up with any answer other than that she's just a good person.","TWN":"(TWN)그냥, 좋은 녀석이란 것 말고는 다른 답이 안 나오더라고요."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};